from __future__ import annotations

from io import StringIO
from pathlib import Path
import base64
import gzip
import json

import matplotlib.pyplot as plt
import numpy as np
import pandas as pd
import scienceplots  # noqa: F401
from matplotlib.colors import ListedColormap

# Frozen source data extracted from results/tables/muraro_case_study_source_data.csv
# and seed metrics produced by the original checkpoint-based script.
# Embedded for single-file figure reproducibility.
FROZEN_SOURCE_B64 = """"""
FROZEN_SUMMARY_JSON = """[{"seed":1,"ARI":0.889373,"NMI":0.854866},{"seed":42,"ARI":0.894079,"NMI":0.853114},{"seed":84,"ARI":0.891285,"NMI":0.850949}]"""
BEST_SEED = 42

ROOT = Path(__file__).resolve().parents[1]
OUT_FIG = ROOT / "generated_figures" / "fig_case_muraro_iter2.pdf"
OUT_CSV = ROOT / "generated_tables" / "muraro_case_study_source_data.csv"

plt.style.use(["science", "nature", "no-latex"])
plt.rcParams.update({"figure.dpi": 200, "savefig.dpi": 300, "font.size": 9, "axes.titlesize": 10, "axes.labelsize": 9, "legend.fontsize": 7, "xtick.labelsize": 8, "ytick.labelsize": 8, "pdf.fonttype": 42, "ps.fonttype": 42})


def load_source_df() -> pd.DataFrame:
    raw = gzip.decompress(base64.b64decode(FROZEN_SOURCE_B64)).decode()
    return pd.read_csv(StringIO(raw))


def load_summary_df() -> pd.DataFrame:
    return pd.DataFrame(json.loads(FROZEN_SUMMARY_JSON)).sort_values('seed').reset_index(drop=True)


def make_palette(n: int):
    base = plt.get_cmap("tab20")(np.linspace(0, 1, max(n, 10)))
    return ListedColormap(base[:n])


def align_cluster_colors(pred_labels, true_labels):
    true_cat = pd.Categorical(true_labels)
    true_codes = true_cat.codes
    mapping = {}
    for cluster in pd.unique(pred_labels):
        mask = pred_labels == cluster
        vals, cnts = np.unique(true_codes[mask], return_counts=True)
        mapping[cluster] = vals[np.argmax(cnts)]
    return np.array([mapping[c] for c in pred_labels]), len(true_cat.categories)


def plot_case(best_df: pd.DataFrame, summary_df: pd.DataFrame):
    tsne = best_df[["tsne_1", "tsne_2"]].to_numpy()
    true_labels = best_df["cell_type"].to_numpy()
    pred_labels = best_df["pred_cluster"].to_numpy()
    unique_true = pd.Index(sorted(pd.unique(true_labels)))
    true_codes = pd.Categorical(true_labels, categories=unique_true).codes
    aligned_pred_codes, aligned_n = align_cluster_colors(pred_labels, true_labels)
    confusion_df = pd.crosstab(best_df["pred_cluster"], best_df["cell_type"], normalize="index")

    fig = plt.figure(figsize=(9.8, 6.6))
    gs = fig.add_gridspec(2, 2, width_ratios=[1.1, 1.0], height_ratios=[1.0, 0.80], hspace=0.26, wspace=0.18)
    ax1 = fig.add_subplot(gs[0, 0]); ax2 = fig.add_subplot(gs[0, 1]); ax3 = fig.add_subplot(gs[1, 0]); ax4 = fig.add_subplot(gs[1, 1])

    s = 10
    ax1.scatter(tsne[:, 0], tsne[:, 1], c=true_codes, s=s, cmap=make_palette(len(unique_true)), linewidths=0, alpha=0.9)
    ax1.set_title("Muraro pancreas: ground-truth cell types")
    ax1.set_xlabel("t-SNE 1"); ax1.set_ylabel("t-SNE 2")

    best_row = summary_df.loc[summary_df["ARI"].idxmax()]
    ax2.scatter(tsne[:, 0], tsne[:, 1], c=aligned_pred_codes, s=s, cmap=make_palette(aligned_n), linewidths=0, alpha=0.9)
    ax2.set_title(f"scAGCR clustering (best seed={int(best_row['seed'])}, ARI={best_row['ARI']:.3f})")
    ax2.set_xlabel("t-SNE 1"); ax2.set_ylabel("t-SNE 2")

    im = ax3.imshow(confusion_df.values, aspect="auto", cmap="YlGnBu")
    ax3.set_title("Predicted cluster vs. cell-type composition")
    ax3.set_xticks(range(confusion_df.shape[1]), confusion_df.columns, rotation=45, ha="right")
    ax3.set_yticks(range(confusion_df.shape[0]), [f"C{i+1}" for i in range(len(confusion_df.index))])
    for i in range(confusion_df.shape[0]):
        for j in range(confusion_df.shape[1]):
            val = confusion_df.values[i, j]
            if val > 0.05:
                ax3.text(j, i, f"{val:.2f}", ha="center", va="center", fontsize=6, color="white" if val > 0.45 else "black")
    fig.colorbar(im, ax=ax3, fraction=0.046, pad=0.04)

    x = np.arange(len(summary_df))
    ax4.errorbar(summary_df["seed"].astype(str), summary_df["ARI"], yerr=None, fmt="o", color="#2A9D8F", ms=6)
    mean_ari = summary_df["ARI"].mean(); std_ari = summary_df["ARI"].std(ddof=1)
    ax4.axhline(mean_ari, color="#33658A", lw=1.5, label=f"mean={mean_ari:.3f}")
    ax4.fill_between(x, mean_ari - std_ari, mean_ari + std_ari, color="#33658A", alpha=0.15, step="mid")
    ax4.set_xticks(x, summary_df["seed"].astype(str))
    ax4.set_ylim(max(0.88, summary_df["ARI"].min() - 0.01), min(0.96, summary_df["ARI"].max() + 0.01))
    ax4.set_title("Seed reproducibility")
    ax4.set_xlabel("Seed"); ax4.set_ylabel("ARI")
    ax4.legend(frameon=False, loc="lower right")

    for ax in [ax1, ax2]:
        ax.set_xticks([]); ax.set_yticks([])
        for spine in ax.spines.values():
            spine.set_visible(False)

    fig.savefig(OUT_FIG, bbox_inches="tight")
    plt.close(fig)


def main():
    source_df = load_source_df()
    summary_df = load_summary_df()
    source_df.to_csv(OUT_CSV, index=False)
    best_df = source_df.copy()
    plot_case(best_df, summary_df)
    print(f"Saved case-study figure to {OUT_FIG}")
    print(f"Saved source data to {OUT_CSV}")
    print(summary_df.to_string(index=False))


if __name__ == "__main__":
    main()
